/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchTable, ButtonInterCompanySalesTableTP), FormControlEventType::Clicked)]
public static void ButtonInterCompanySalesTableTP_OnClicked(FormControl sender, FormControlEventArgs e)
{
    SalesTable        salestable;
    FormButtonControl callerButton = sender as FormButtonControl;  
    FormDataSource formDS          = sender.formRun().dataSource('PurchTable');
    PurchTable     purchTable      = formDS.cursor();

    MenuFunction menuFunction = new MenuFunction(menuitemdisplaystr(SalesTable), MenuItemType::Display);
    Args args  = new Args();
    salestable = SalesTable::find(purchTable.ETG_TPSalesId);
    args.record(salestable);
    menuFunction.run(args);

}

[FormControlEventHandler(formControlStr(PurchTable, BuyerDeliveryRef), FormControlEventType::Lookup)]
public static void  BuyerDeliveryRef_OnLookup(FormControl sender, FormControlEventArgs e)
{

    ETG_PurchTableHandlers::createLookup(sender);

    FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
    cancelableArgs.CancelSuperCall();
}

private static void createLookup(FormReferenceGroupControl _ctrl)
{
    SysReferenceTableLookup     sysTableLookup  = SysReferenceTableLookup::newParameters(tablenum(LogisticsPostalAddress), _ctrl);
    Query                       lookupQuery = new Query();
    QueryBuildDataSource        lookupQry   = new QueryBuildDataSource();
    CompanyInfo                 companyInfo;
    DirPartyTable               dirPartyTable;
    DirPartyLocation            dirPartyLocation;
    LogisticsPostalAddress      logisticsPostalAddress;
    SysReferenceTableLookup     sysRefTableLookup;
    QuerybuildDatasource        qbd, qbd1, qbd2, qbd3, qbd4;

    qbd     = lookupQuery.addDataSource(tablenum(LogisticsPostalAddress));
    qbd1    = qbd.addDataSource(tablenum(DirPartyLocation));
    qbd1.addLink(fieldNum(LogisticsPostalAddress, Location), fieldNum(DirPartyLocation, Location));
    qbd1.joinMode(JoinMode::InnerJoin);

    qbd2 = qbd1.addDataSource(tablenum(CompanyInfo));
    qbd2.addLink(fieldNum(DirPartyLocation, Party), (fieldNum(CompanyInfo, RecId)));
    qbd2.joinMode(JoinMode::InnerJoin);

    qbd2.addRange(fieldnum(CompanyInfo, DataArea)).value(SysQuery::value(curext()));

    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Location));
    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Street));

    sysTableLookup.parmQuery(lookupQuery);
    sysTableLookup.performFormLookup();
}

[FormControlEventHandler(formControlStr(PurchTable, SellerDeliveryRef), FormControlEventType::Lookup)]
public static void  SellerDeliveryRef_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormDataSource          purchTable_ds       = sender.formRun().dataSource('ETG_PurchTableTrade');
    ETG_PurchTableTrade    purchTableTradeETG   = purchTable_ds.cursor();

    ETG_PurchTableHandlers::sellerLookup(sender,purchTableTradeETG.SellerAccountNum);

    FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
    cancelableArgs.CancelSuperCall();
}

private static void sellerLookup(FormReferenceGroupControl _ctrl,VendAccount _vendAccount)
{
    SysReferenceTableLookup     sysTableLookup  = SysReferenceTableLookup::newParameters(tablenum(LogisticsPostalAddress), _ctrl);
    Query                       lookupQuery = new Query();
    QueryBuildDataSource        lookupQry   = new QueryBuildDataSource();
    CompanyInfo                 companyInfo;
    DirPartyTable               dirPartyTable;
    DirPartyLocation            dirPartyLocation;
    LogisticsPostalAddress      logisticsPostalAddress;
    SysReferenceTableLookup     sysRefTableLookup;
    QuerybuildDatasource        qbd, qbd1, qbd2, qbd3, qbd4;

    qbd     = lookupQuery.addDataSource(tablenum(LogisticsPostalAddress));
    qbd1    = qbd.addDataSource(tablenum(DirPartyLocation));
    qbd1.addLink(fieldNum(LogisticsPostalAddress, Location), fieldNum(DirPartyLocation, Location));
    qbd1.joinMode(JoinMode::InnerJoin);

    qbd2 = qbd1.addDataSource(tablenum(VendTable));
    qbd2.addLink(fieldNum(DirPartyLocation, Party), (fieldNum(VendTable, Party)));
    qbd2.joinMode(JoinMode::InnerJoin);

    qbd2.addRange(fieldnum(VendTable, AccountNum)).value(SysQuery::value(_vendAccount));

    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Location));
    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Street));

    sysTableLookup.parmQuery(lookupQuery);
    sysTableLookup.performFormLookup();
}

