/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchTable, GroupIdLine), FormControlEventType::Modified)]
public static void GroupIdLine_OnModified(FormControl sender, FormControlEventArgs e)
{
    PurchLine                          purchLine;
    ETG_ProductReceiptQualityGrp       productReceiptQualityGrp;
    ETG_QualitySubGrpView              qualitySubGrpView;
    Name        grpId   = sender.valueStr();

    FormDataSource  purchLine_ds   = sender.formRun().dataSource(formDataSourceStr(PurchTable,PurchLine))  as FormDataSource;
    purchLine                      = purchLine_ds.cursor();

    while select * from qualitySubGrpView
        where qualitySubGrpView.GroupID == grpId
    {
        productReceiptQualityGrp.MinRange       = qualitySubGrpView.MinRange;
        productReceiptQualityGrp.MaxRange       = qualitySubGrpView.MaxRange;
        productReceiptQualityGrp.AdjustmentType = qualitySubGrpView.AdjustmentType;
        productReceiptQualityGrp.Increment      = qualitySubGrpView.Increment;
        productReceiptQualityGrp.FixedValue     = qualitySubGrpView.FixedValue;
        productReceiptQualityGrp.SubGroupID     = qualitySubGrpView.SubGroupID;          
        productReceiptQualityGrp.InventTransId  = purchLine.InventTransId;
        productReceiptQualityGrp.PurchId        = purchLine.PurchId;
        productReceiptQualityGrp.GroupID               = qualitySubGrpView.GroupID;
        productReceiptQualityGrp.GroupDescription      = qualitySubGrpView.GroupDescription;
        productReceiptQualityGrp.SubGroupDescription   = qualitySubGrpView.SubGroupDescription;
        productReceiptQualityGrp.insert();
    }
}

