    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormControlEventHandler(formControlStr(PurchTable, Notifytodifferentparty), FormControlEventType::Modified)]
    public static void Notifytodifferentparty_OnModified(FormControl sender, FormControlEventArgs e)
    {
        ETG_PurchTableTrade purchTabletradeETG = sender.formRun().dataSource().cursor();
        FormRun             element       = sender.formRun(); //form element
        FormControl         NotifyName   = element.design(0).controlName("NotifyName");
        FormControl         NotifyAddress   = element.design(0).controlName("NotifyAddress");

        if(purchTabletradeETG.Notifytodifferentparty == NoYes::yes)// && purchTabletradeETG.Consignee && purchTabletradeETG.OnAccountOf)
        {
            NotifyName.enabled(true);
            NotifyAddress.enabled(true);
        }
        else if(purchTabletradeETG.Notifytodifferentparty == NoYes::No) //&& purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
        {
            purchTabletradeETG.Name = "";
            purchTabletradeETG.Address = "";
            NotifyName.enabled(false);
            NotifyAddress.enabled(false);
        }
    }

[FormControlEventHandler(formControlStr(PurchTable, ShipmentTabPage), FormControlEventType::PageActivated)]
public static void ShipmentTabPage_OnPageActivated(FormControl sender, FormControlEventArgs e)
{
    ETG_PurchTableTrade purchTabletradeETG = sender.formRun().dataSource().cursor();
    FormRun             element       = sender.formRun(); //form element
    FormControl         NotifyName   = element.design(0).controlName("NotifyName");
    FormControl         NotifyAddress   = element.design(0).controlName("NotifyAddress");

    if(purchTabletradeETG.Notifytodifferentparty == NoYes::Yes)// && purchTabletradeETG.Consignee && purchTabletradeETG.OnAccountOf)
    {
        NotifyName.enabled(true);
        NotifyAddress.enabled(true);
    }
    else if(purchTabletradeETG.Notifytodifferentparty == NoYes::No) //&& purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
    {
        purchTabletradeETG.Name = "";
        purchTabletradeETG.Address = "";
        NotifyName.enabled(false);
        NotifyAddress.enabled(false);
    }

}

/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchTable, BuyerBankString), FormControlEventType::Modified)]
public static void BuyerBankString_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_PurchTableTrade purchTabletradeETG = sender.formRun().dataSource(FormDataSourcestr(PurchTable, ETG_PurchTableTrade)).cursor();
    FormDataSource      ETG_PurchTableTrade_ds =  sender.formRun().dataSource(FormDataSourcestr(PurchTable, ETG_PurchTableTrade));
        purchTabletradeETG.BuyerSecondaryBank = purchTabletradeETG.BuyerBank;

    if (purchTabletradeETG.BuyerSecondaryBank == '' || purchTabletradeETG.BuyerBank == '')
    {
        ETG_PurchTableTrade_ds.object(fieldNum(ETG_PurchTableTrade, BuyerSecondaryBank)).allowEdit(true);
    }
    else
    {
        ETG_PurchTableTrade_ds.object(fieldNum(ETG_PurchTableTrade, BuyerSecondaryBank)).allowEdit(false);
    }


}

