/// <summary>
[FormControlEventHandler(formControlStr(PurchTable, PlaceOfLoading), FormControlEventType::Modified)]
public static void PlaceOfLoading_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_PurchTableTrade purchTabletradeETG = sender.formRun().dataSource(FormDataSourcestr(PurchTable, ETG_PurchTableTrade)).cursor();
    FormDataSource      ETG_PurchTableTrade_ds =  sender.formRun().dataSource(FormDataSourcestr(PurchTable, ETG_PurchTableTrade));
    ETG_PlaceOfLoading      placeofLoading;

    select firstonly placeofLoading
        where placeofLoading.PlaceOfLoading == purchTabletradeETG.PortOfLoading;

    purchTabletradeETG.PortOfLoadingDesc = placeofLoading.Description;

    if (purchTabletradeETG.PortOfLoadingDesc == '' || purchTabletradeETG.PortOfLoading == '')
    {
        ETG_PurchTableTrade_ds.object(fieldNum(ETG_PurchTableTrade, PortOfLoadingDesc)).allowEdit(true);
    }
    else
    {
        ETG_PurchTableTrade_ds.object(fieldNum(ETG_PurchTableTrade, PortOfLoadingDesc)).allowEdit(false);
    }
}

