/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchTable, SellerBankString), FormControlEventType::Lookup)]
public static void SellerBankString_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(curExt() == "O001")
    {
        FormRun                 formRun;
        FormDataSource          purchTableDS;
        PurchTable              purchTable;
        SysTableLookup          sysTableLookup;
        Query                   query;
        QueryBuildDataSource    qbds;

        formRun = sender.formRun();

        purchTableDS = formRun.dataSource(formDataSourceStr(PurchTable, PurchTable)) as FormDataSource;

        purchTable = purchTableDS.cursor();

        query = new Query();
        qbds = query.addDataSource(tableNum(VendBankAccount));

        qbds.addRange(fieldNum(VendBankAccount, VendAccount)).value(queryValue(purchTable.OrderAccount));

        sysTableLookup = SysTableLookup::newParameters(tableNum(VendBankAccount),sender);

        sysTableLookup.addLookupField(fieldNum(VendBankAccount, AccountID));
        sysTableLookup.addLookupField(fieldNum(VendBankAccount, AccountNum));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
        cancelableArgs.CancelSuperCall();
    }
}

/// <summary>
/// Sets the payment terms field to be mandatory based on the legal entity.
/// </summary>
/// <param name="sender">The form datasource (PurchTable).</param>
/// <param name="e">Event arguments.</param>
[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchTable), FormDataSourceEventType::Activated)]
public static void purchTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{

    FormRun formRun = sender.formRun();


    str controlName = formControlStr(PurchTable, Payment_Payment);


    FormStringControl paymentControl = formRun.design().controlName(controlName) as FormStringControl;

    if (paymentControl)
    {

        paymentControl.mandatory(true);
    }
}
